import React from 'react';
import { useNavigate } from 'react-router-dom';
import logo from './assets/logo.png';

function Home() {
  const navigate = useNavigate();

  return (
    <div style={styles.container}>

      {/* LOGO */}
      <img src={logo} alt="GRC" style={styles.logo} />

      {/* CARD PRINCIPAL */}
      <div style={styles.card}>
        <h1 style={styles.title}>Sistema de Gestão de Reclamações</h1>

        <p style={styles.subtitle}>
          Painel corporativo para gestão, controle e tratativa de demandas
        </p>

        <div style={styles.buttons}>
          <button
            style={styles.primaryButton}
            onClick={() => navigate('/cadastro')}
          >
            ➕ Nova Reclamação
          </button>

          <button
            style={styles.secondaryButton}
            onClick={() => navigate('/dashboard')}
          >
            📊 Dashboard / Gestão
          </button>
        </div>
      </div>

    </div>
  );
}

const styles = {
  container: {
    height: '100vh',
    background: 'linear-gradient(135deg, #1e3c72, #2a5298)',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    flexDirection: 'column'
  },

  logo: {
    width: 180,
    marginBottom: 20
  },

  card: {
    background: '#fff',
    padding: 40,
    borderRadius: 12,
    width: 420,
    boxShadow: '0 15px 40px rgba(0,0,0,0.2)',
    textAlign: 'center'
  },

  title: {
    marginBottom: 10,
    color: '#1e3c72'
  },

  subtitle: {
    fontSize: 14,
    color: '#666',
    marginBottom: 30
  },

  buttons: {
    display: 'flex',
    flexDirection: 'column',
    gap: 15
  },

  primaryButton: {
    padding: 15,
    background: '#1e88e5',
    color: '#fff',
    border: 'none',
    borderRadius: 8,
    fontSize: 16,
    cursor: 'pointer',
    transition: '0.3s'
  },

  secondaryButton: {
    padding: 15,
    background: '#43a047',
    color: '#fff',
    border: 'none',
    borderRadius: 8,
    fontSize: 16,
    cursor: 'pointer'
  }
};

export default Home;
